## Tests

```rust
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn leaves_absolute_path_unchanged() {
        assert_eq!(expand_tilde("/etc/ssh/key.pub"), "/etc/ssh/key.pub");
    }

    #[test]
    fn leaves_non_tilde_unchanged() {
        assert_eq!(expand_tilde("relative/path"), "relative/path");
    }

    #[test]
    fn expands_tilde_slash() {
        // Works on both platforms if HOME / USERPROFILE is set
        let result = expand_tilde("~/.ssh/id_ed25519.pub");
        assert!(!result.starts_with('~'));
        assert!(result.ends_with(".ssh/id_ed25519.pub"));
    }

    #[test]
    #[cfg(windows)]
    fn expands_tilde_backslash() {
        let result = expand_tilde("~\\.ssh\\id_ed25519.pub");
        assert!(!result.starts_with('~'));
    }
}
